                  'h-2 w-2 rounded-full shrink-0',
                  isAvailable ? 'bg-emerald-500' : 'bg-red-400',
                )} />
                <span className="font-medium truncate">{formatProviderName(provider.key)}</span>
                {isActive && (
                  <Badge variant="default" className="text-[9px] ml-1 px-1.5 py-0">
                    ACTIVE
                  </Badge>
